// Get the AI Agent's response
const aiResponse = $input.first().json.output;

// Check if the response contains booking confirmation
if (aiResponse && aiResponse.includes('BOOKING_CONFIRMED:')) {
  try {
    // Extract JSON from the response
    const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);

    if (jsonMatch) {
      const bookingData = JSON.parse(jsonMatch[0]);

      // Return booking data with a confirmation flag
      return [{
        json: {
          confirmed: true,
          name: bookingData.name,
          phone: bookingData.phone,
          email: bookingData.email || '',
          date: bookingData.date,
          time: bookingData.time
        }
      }];
    }
  } catch (error) {
    // If parsing fails, return not confirmed
    return [{
      json: {
        confirmed: false,
        message: 'Parsing error',
        rawResponse: aiResponse
      }
    }];
  }
}

// No confirmation found - still in conversation
return [{
  json: {
    confirmed: false,
    message: 'Conversation ongoing'
  }
}];

// Check if items array is empty or contains only empty objects
if (!items || items.length === 0) {
  return [
    {
      json: {
        message: "No slots are available at the moment.",
        availability: {},
        hasSlots: false
      }
    }
  ];
}

// Check if first item has no data (empty object)
if (!items[0].json.available_date || !items[0].json.available_time) {
  return [
    {
      json: {
        message: "No slots are available at the moment.",
        availability: {},
        hasSlots: false
      }
    }
  ];
}

const availability = {};

for (const item of items) {
  // Skip items with missing data
  if (!item.json.available_date || !item.json.available_time) {
    continue;
  }

  const date = item.json.available_date;
  const time = item.json.available_time.slice(0, 5); // HH:mm

  if (!availability[date]) {
    availability[date] = [];
  }
  if (!availability[date].includes(time)) {
    availability[date].push(time);
  }
}

// Sort times for each date
for (const date in availability) {
  availability[date].sort();
}

// Check if availability object is still empty after processing
if (Object.keys(availability).length === 0) {
  return [
    {
      json: {
        message: "No slots are available at the moment.",
        availability: {},
        hasSlots: false
      }
    }
  ];
}

return [
  {
    json: {
      message: "Available slots found",
      availability: availability,
      hasSlots: true
    }
  }
];
